import React, { useState } from 'react';
import { FaBars, FaTimes } from 'react-icons/fa';
import logo from '../Assets/logo.png';
import '../index.css';
import { Link } from 'react-router-dom';

const Header = () => {

    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    const toggleMobileMenu = () => {
        setIsMobileMenuOpen(!isMobileMenuOpen);
    };

    return (
      
        <header className="bg-[#1c274c] p-4">
            <div className="container mx-auto flex justify-between items-center">
                <div className="flex items-center">
                    <img src={logo} alt="Crib Cleaners" className="h-8 w-auto mr-2" />
                </div>
                  <nav>
        <ul className="hidden md:flex space-x-8 ml-2 mr-4 text-white font-semibold text-base tracking-wider uppercase">
          <li><Link to="/Home.js relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Home</Link></li>
          <li><Link to="/Services.js relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Services</Link></li>
          <li><Link to="/About.js relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">About</Link></li>
          <li><Link to="/Contact.js relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Contact</Link></li>
        </ul>
      </nav>
                <div className="hidden md:flex space-x-8 ml-2 mr-4 text-white font-semibold text-base tracking-wider uppercase">
                    <a href="#home" className="relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Home</a>
                    <a href="#services" className="relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Services</a>
                    <a href="#about" className="relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">About</a>
                    <a href="#contact" className="relative after:absolute after:left-0 after:bottom-0 after:w-full after:h-[2px] after:bg-current after:scale-x-0 after:origin-bottom-right after:transition-transform after:duration-300 hover:after:scale-x-100 hover:after:origin-bottom-left">Contact</a>
                </div>
                <div className="md:hidden">
                    <button onClick={toggleMobileMenu} className="text-white focus:outline-none">
                        {isMobileMenuOpen ? <FaTimes size={24} /> : <FaBars size={24} />}
                    </button>
                </div>
            </div>
            {isMobileMenuOpen && (
                 <div className={`fixed inset-0 bg-black mt-16 flex flex-col items-center justify-start z-50 transform transition-transform duration-300`}>
                 <ul className="space-y-6 text-white font-semibold text-xl tracking-wider uppercase text-center">
                     <li className={`staggered-item`}>
                         <a href="#home" className="hover:underline" onClick={toggleMobileMenu}>Home</a>
                     </li>
                     <li className={`staggered-item`}>
                         <a href="#services" className="hover:underline" onClick={toggleMobileMenu}>Services</a>
                     </li>
                     <li className={`staggered-item`}>
                         <a href="#about" className="hover:underline" onClick={toggleMobileMenu}>About</a>
                     </li>
                     <li className={`staggered-item`}>
                         <a href="#contact" className="hover:underline" onClick={toggleMobileMenu}>Contact</a>
                     </li>
                 </ul>
             </div>
             )}
        </header>
    );
};

export default Header;
